css:
.bv-root{--bv-navy:#485995;--bv-navy-deep:#36436f;--bv-gold:#d2c600;--bv-gold-deep:#8f8600;--bv-ink:#141922;--bv-muted:#5b6472;--bv-paper:#fff;--bv-bg:#eef1f7;--bv-line:#cdd2e0;--field:#f4f6fb;--field-line:#d3d9e8;--route:#b58a00;--navy:#485995;--dline:#737d90;--paper:#fff;--muted:#5b6472;--good:#2f8f5b;--bad:#c0453b;--warn:#c8871a;color:var(--bv-ink);background:var(--bv-bg);min-height:100vh}
@media(prefers-color-scheme:dark){.bv-root{--bv-ink:#e9edf6;--bv-muted:#9aa3b7;--bv-paper:#161c2e;--bv-bg:#0b0f1a;--bv-line:#2a3350;--field:#10162a;--field-line:#232c48;--route:#e0b23a;--navy:#8fa3df;--dline:#828ca4;--paper:#161c2e;--muted:#9aa3b7}}
.dark .bv-root{--bv-ink:#e9edf6;--bv-muted:#9aa3b7;--bv-paper:#161c2e;--bv-bg:#0b0f1a;--bv-line:#2a3350;--field:#10162a;--field-line:#232c48;--route:#e0b23a;--navy:#8fa3df;--dline:#828ca4;--paper:#161c2e;--muted:#9aa3b7}
.bv-container{max-width:1120px;margin:0 auto;padding:86px 14px 80px}
.bv-hero{background:linear-gradient(135deg,var(--bv-navy-deep),var(--bv-navy));color:#fff;border-radius:18px;padding:26px 28px;position:relative;overflow:hidden;box-shadow:0 14px 40px rgba(17,24,39,.16)}
.bv-hero::after{content:"";position:absolute;right:-40px;top:-60px;width:240px;height:240px;border-radius:50%;background:radial-gradient(circle,rgba(210,198,0,.28),transparent 68%)}
.bv-eye{font-size:11.5px;letter-spacing:.16em;text-transform:uppercase;color:var(--bv-gold);font-weight:600}
.bv-hero h1{margin:.25em 0 .12em;font-size:clamp(24px,4vw,34px);letter-spacing:-.02em;line-height:1.04}
.bv-hero p{margin:0;color:rgba(255,255,255,.86);max-width:70ch;font-size:14px}
.bv-herolinks{display:flex;flex-wrap:wrap;gap:10px;margin-top:16px}
.bv-herolinks a{font-size:12.5px;font-weight:600;text-decoration:none;color:#fff;background:rgba(255,255,255,.14);border:1px solid rgba(255,255,255,.28);padding:7px 13px;border-radius:999px}
.bv-herolinks a:hover{background:rgba(255,255,255,.24)}
.bv-panel{background:var(--bv-paper);border:1px solid var(--bv-line);border-radius:16px;padding:20px 22px;margin-top:16px;box-shadow:0 10px 28px rgba(17,24,39,.06)}
.bv-panel h2{margin:0 0 4px;font-size:17px;color:var(--bv-ink)}
.bv-panel .sub{color:var(--bv-muted);font-size:13px;margin:0 0 16px}
.bv-score{display:grid;grid-template-columns:1fr;gap:0;border:1px solid var(--bv-line);border-radius:12px;overflow:hidden;margin-bottom:18px}
.bv-scrow{display:grid;grid-template-columns:1.6fr 1fr 1fr;align-items:center;font-size:13px;border-bottom:1px solid var(--bv-line)}
.bv-scrow:last-child{border-bottom:none}
.bv-scrow>div{padding:9px 13px}
.bv-scrow .dim{color:var(--bv-muted)}
.bv-scrow .old{color:var(--bad);border-left:1px solid var(--bv-line);font-weight:600}
.bv-scrow .new{color:var(--good);border-left:1px solid var(--bv-line);font-weight:700}
.bv-scrow.head>div{background:var(--field);font-size:10.5px;letter-spacing:.06em;text-transform:uppercase;color:var(--bv-navy);font-weight:700;padding:8px 13px}
.bv-scrow.total>div{background:color-mix(in srgb,var(--bv-gold) 12%,var(--bv-paper))}
.bv-scrow .big{font-size:20px;font-variant-numeric:tabular-nums}
.bv-cols{display:grid;grid-template-columns:repeat(auto-fit,minmax(230px,1fr));gap:16px}
.bv-cols h3{font-size:12px;letter-spacing:.05em;text-transform:uppercase;color:var(--bv-navy);margin:0 0 6px}
.bv-cols ul,.bv-cols ol{margin:0;padding-left:1.1em;font-size:12.5px;color:var(--bv-muted);line-height:1.5}
.bv-cols li b{color:var(--bv-ink)}
.bv-cols .wk{color:var(--bv-navy);font-weight:700}
.bv-filterwrap{position:absolute;opacity:0;pointer-events:none}
.bv-toolbar{display:flex;flex-wrap:wrap;align-items:center;gap:10px;margin:18px 4px 0;font-size:13px;color:var(--bv-muted)}
.bv-toggle{cursor:pointer;border:1px solid var(--bv-line);background:var(--bv-paper);color:var(--bv-ink);padding:7px 14px;border-radius:999px;font-weight:600;font-size:12.5px;user-select:none}
.bv-btn{cursor:pointer;border:1px solid var(--bv-line);background:var(--bv-paper);color:var(--bv-ink);padding:7px 13px;border-radius:999px;font-weight:600;font-size:12.5px;font-family:inherit}
.bv-btn:hover,.bv-toggle:hover{border-color:var(--bv-navy)}
#bvCoreOnly:checked ~ .bv-toolbar .bv-toggle{background:var(--bv-gold);border-color:var(--bv-gold-deep);color:#141922}
#bvCoreOnly:checked ~ #bvPlays .bv-card:not(.is-core){display:none}
#bvCoreOnly:checked ~ #bvPlays .bv-groupwrap:not(:has(.is-core)){display:none}
.bv-group{font-size:16px;margin:26px 4px 4px;padding-bottom:6px;border-bottom:2px solid var(--bv-line);color:var(--bv-ink);display:flex;align-items:baseline;gap:8px}
.bv-group .ct{font-size:12px;color:var(--bv-muted);font-weight:400}
.bv-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(340px,1fr));gap:16px;margin-top:12px}
.bv-card{background:var(--bv-paper);border:1px solid var(--bv-line);border-radius:14px;overflow:hidden;box-shadow:0 10px 28px rgba(17,24,39,.08);transition:box-shadow .15s,transform .15s}
.bv-card:hover{box-shadow:0 16px 38px rgba(17,24,39,.13);transform:translateY(-2px)}
.bv-card.is-core{border-color:color-mix(in srgb,var(--bv-gold) 60%,var(--bv-line));box-shadow:0 10px 28px rgba(210,198,0,.12)}
.bv-cap{padding:11px 14px 4px;font-weight:700;font-size:14.5px;color:var(--bv-navy);display:flex;align-items:center;gap:7px}
.bv-badge{font-size:9px;font-weight:700;letter-spacing:.05em;background:var(--bv-gold);color:#141922;padding:2px 7px;border-radius:5px}
.bv-opp{padding:0 14px 4px;font-size:11px;color:var(--bv-muted)}
.field{width:100%;height:auto;display:block;background:var(--field);border-top:1px solid var(--field-line)}
img.field{background:#fff}
.bv-note{padding:9px 14px 12px;font-size:12px;color:var(--bv-muted);line-height:1.45;border-top:1px solid var(--bv-line)}
.bv-note b{color:var(--bv-navy)}
.bv-note .coach{display:block;margin-bottom:5px}
.bv-note .scheme{display:block;padding-top:5px;border-top:1px dashed var(--bv-line);color:var(--bv-muted)}
.bv-note .scheme b{color:var(--bv-gold-deep)}
.bv-foot{margin-top:34px;text-align:center;color:var(--bv-muted);font-size:12px}
.bv-bar{height:3px;width:100px;margin:0 auto 10px;border-radius:999px;background:linear-gradient(90deg,var(--bv-navy),var(--bv-gold))}
@media print{@page{margin:8mm}.bv-root{background:#fff}.bv-hero,.bv-card,.bv-panel{box-shadow:none}.bv-card{break-inside:avoid}.bv-grid{grid-template-columns:repeat(2,1fr)}.bv-toolbar,.bv-herolinks{display:none}}
